 91→Event-driven, regex parsing for value+unit.
 92→
 93→```csharp
 94→private static readonly Regex NumUnitRegex =
 95→    new(@"([+-]?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)([A-Za-z%µ]*)");
 96→
 97→// Query:  ID{id:D2}P\r\n    → Response: ID,{id},{value}{unit}\r\n
 98→// Stream: continuous ST,NT,+01234.5\r\n (set F-40=000, F-42=0)
 99→// Zero:   ID{id}Z\r\n
100→
101→private void ParseLine(string line)
102→{
103→    var parts = line.Split(',');
104→    if (parts.Length >= 3)
105→    {
106→        var match = NumUnitRegex.Match(parts[2]);
107→        if (match.Success)
108→        {
109→            Value = double.Parse(match.Groups[1].Value);
110→            Unit = match.Groups[2].Value;
111→            ValueReceived?.Invoke(Value, Unit);
112→        }
113→    }
114→}
