132→        {
133→            byte[] buffer = new byte[12];  // 패킷 크기: Header(1) + DI(2) + AI(8) + Checksum(1)
134→            int readIndex = 0;
135→
136→            while (SerialAduino.IsOpen)
137→            {
138→                try
139→                {
140→                    int available = SerialAduino.BytesToRead;
141→                    if (available > 0)
142→                    {
143→                        // 헤더 찾기
144→                        if (readIndex == 0)
145→                        {
146→                            byte b = (byte)SerialAduino.ReadByte();
147→                            if (b == 0x52)  // 헤더 확인
148→                            {
149→                                buffer[0] = b;
150→                                readIndex = 1;
151→                            }
152→                        }
153→                        else
154→                        {
155→                            // 나머지 패킷 읽기
156→                            int bytesToRead = Math.Min(12 - readIndex, available);
157→                            int bytesRead = SerialAduino.Read(buffer, readIndex, bytesToRead);
158→                            readIndex += bytesRead;
159→
160→                            // 패킷 완성되면 파싱
161→                            if (readIndex >= 12)
162→                            {
163→                                // 체크섬 검증
164→                                byte checksum = 0;
165→                                for (int i = 1; i < 11; i++)  // Header와 Checksum 제외
166→                                {
167→                                    checksum ^= buffer[i];
168→                                }
169→
170→                                if (checksum == buffer[11])
171→                                {
172→                                    // DI 파싱 (Little Endian, 16비트 전체)
173→                                    ushort diValue = (ushort)(buffer[1] | (buffer[2] << 8));
174→                                    for (int i = 0; i < 16; i++)
175→                                    {
176→                                        IO.IN[i] = ((diValue >> i) & 1) == 1;
177→                                    }
178→
179→                                    // UI 업데이트 - btnIn은 8개만
