192→                                                btnIn[i].ForeColor = System.Drawing.Color.White;
193→                                            }
194→                                        }
195→                                    }));
196→
197→                                    // AI 파싱 (Little Endian)
198→                                    ushort ai0 = (ushort)(buffer[3] | (buffer[4] << 8));
199→                                    ushort ai1 = (ushort)(buffer[5] | (buffer[6] << 8));
200→                                    ushort ai2 = (ushort)(buffer[7] | (buffer[8] << 8));
201→                                    ushort ai3 = (ushort)(buffer[9] | (buffer[10] << 8));
202→
203→                                    // ADC 값 -> 실제 물리값 변환 (모드별 분기)
204→                                    if (GlobalValues.weldMode == "SPOT")
205→                                    {
206→                                        // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
207→                                        double ampRaw = (ai0 / 1023.0 * 3.0) * Amp.Tol;
208→                                        double tempRaw = ((ai1 / 1023.0 * 25.0) - 25.0) * Volt.Tol;
209→                                        double airRaw = (((ai2 / 1023.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;
210→
211→                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
212→                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
213→                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
214→                                    }
215→                                    else
216→                                    {
217→                                        // CO2 모드: 전류/전압/유량
218→                                        double ampRaw = (ai0 / 1023.0 * 60.0) * Amp.Tol;
219→                                        double voltRaw = (ai1 / 1023.0 * 25.0) * Volt.Tol;
220→                                        double flowRaw = ((ai2 / 1023.0 * 12.5) - 12.5) * Flow.Tol;
221→
222→                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
223→                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
224→                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
225→                                    }
226→
227→                                    labelAmp.Invoke(new MethodInvoker(() =>
228→                                    {
229→                                        labelAmp.Text = $"{Amp.Value.ToString("0.00")}";
230→                                        labelVolt.Text = $"{Volt.Value.ToString("0.00")}";
231→                                        labelFlow.Text = $"{Flow.Value.ToString("0.00")}";
232→                                    }));
233→                                }
234→                                else
