using System;
using System.IO.Ports;
using System.Linq;
using System.Threading;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public partial class _FrmMain
    {
        // ===== 시리얼 통신 (Arduino V1/V2 프로토콜) =====

        private void ThreadTask1()
        {
            // Arduino SW 버전에 따라 프로토콜 분기
            if (GlobalValues.aduinoSwVer == "2.0")
            {
                ThreadTask1_V2();  // 바이너리 프로토콜 (신규)
            }
            else
            {
                ThreadTask1_V1();  // 텍스트 프로토콜 (기존)
            }
        }

        // v1.0 텍스트 프로토콜 (기존 방식)
        private void ThreadTask1_V1()
        {
            // 시작 시 버퍼 클리어
            if (SerialAduino.BytesToRead > 0)
                SerialAduino.DiscardInBuffer();

            while (SerialAduino.IsOpen)
            {
                try
                {
                    string incoming = SerialAduino.ReadLine();

                    if (!string.IsNullOrEmpty(incoming))
                    {
                        // 버퍼에 쌓인 데이터 있으면 버리고 최신 데이터만 사용
                        if (SerialAduino.BytesToRead > 0)
                            SerialAduino.DiscardInBuffer();

                        string line = incoming.Trim();
                        // 디버그: 수신 데이터 로깅
                        System.Diagnostics.Debug.WriteLine($"[Arduino V1] Raw: '{line}' (len={line.Length})");

                        if (line.StartsWith("S") && line.EndsWith("E") && line.Length == 34)
                        {
                            // DI 파싱 (16비트)
                            for (int i = 0; i < 16; i++)
                            {
                                IO.IN[i] = (line.Substring(i + 1, 1) == "1");
                            }
                            // 디버그: IO.IN 상태 로깅
                            string ioStatus = string.Join("", IO.IN.Take(8).Select(b => b ? "1" : "0"));
                            System.Diagnostics.Debug.WriteLine($"[Arduino V1] IO.IN[0-7]: {ioStatus}");

                            // UI 업데이트 - 비동기 일괄 처리 (btnIn은 8개)
                            this.BeginInvoke(new MethodInvoker(() =>
                            {
                                for (int i = 0; i < btnIn.Length; i++)
                                {
                                    if (IO.IN[i])
                                    {
                                        btnIn[i].BackColor = pColor.Theme.LightRed;
                                        btnIn[i].ForeColor = System.Drawing.Color.Black;
                                    }
                                    else
                                    {
                                        btnIn[i].BackColor = pColor.Theme.DeepRed;
                                        btnIn[i].ForeColor = System.Drawing.Color.White;
                                    }
                                }
                            }));

                            // 아날로그 파싱 (for문 밖에서 1번만)
                            try
                            {
                                double raw1 = Convert.ToDouble(line.Substring(17, 4));
                                double raw2 = Convert.ToDouble(line.Substring(21, 4));
                                double raw3 = Convert.ToDouble(line.Substring(25, 4));

                                if (GlobalValues.weldMode == "SPOT")
                                {
                                    // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
                                    double ampRaw = (raw1 / 100.0 * 3.0) * Amp.Tol;
                                    double tempRaw = ((raw2 / 100.0 * 25.0) - 25.0) * Volt.Tol;
                                    double airRaw = (((raw3 / 100.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;

                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
                                }
                                else
                                {
                                    // CO2 모드: 전류/전압/유량
                                    double ampRaw = (raw1 / 100.0 * 60.0) * Amp.Tol;
                                    double voltRaw = (raw2 / 100.0 * 25.0) * Volt.Tol;
                                    double flowRaw = ((raw3 / 100.0 * 12.5) - 12.5) * Flow.Tol;

                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
                                }

                                // UI 업데이트 - 비동기
                                this.BeginInvoke(new MethodInvoker(() =>
                                {
                                    labelAmp.Text = Amp.Value.ToString("0.00");
                                    labelVolt.Text = Volt.Value.ToString("0.00");
                                    labelFlow.Text = Flow.Value.ToString("0.00");
                                }));
                            }
                            catch (Exception parseEx)
                            {
                                Logger.Log(LanguageManager.Get("log_analog_parse_error", parseEx.Message));
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                }
                Thread.Sleep(1);
            }
        }

        // v2.0 바이너리 프로토콜 (신규)
        private void ThreadTask1_V2()
        {
            byte[] buffer = new byte[12];  // 패킷 크기: Header(1) + DI(2) + AI(8) + Checksum(1)
            int readIndex = 0;

            while (SerialAduino.IsOpen)
            {
                try
                {
                    int available = SerialAduino.BytesToRead;
                    if (available > 0)
                    {
                        // 헤더 찾기
                        if (readIndex == 0)
                        {
                            byte b = (byte)SerialAduino.ReadByte();
                            if (b == 0x52)  // 헤더 확인
                            {
                                buffer[0] = b;
                                readIndex = 1;
                            }
                        }
                        else
                        {
                            // 나머지 패킷 읽기
                            int bytesToRead = Math.Min(12 - readIndex, available);
                            int bytesRead = SerialAduino.Read(buffer, readIndex, bytesToRead);
                            readIndex += bytesRead;

                            // 패킷 완성되면 파싱
                            if (readIndex >= 12)
                            {
                                // 체크섬 검증
                                byte checksum = 0;
                                for (int i = 1; i < 11; i++)  // Header와 Checksum 제외
                                {
                                    checksum ^= buffer[i];
                                }

                                if (checksum == buffer[11])
                                {
                                    // DI 파싱 (Little Endian, 16비트 전체)
                                    ushort diValue = (ushort)(buffer[1] | (buffer[2] << 8));
                                    for (int i = 0; i < 16; i++)
                                    {
                                        IO.IN[i] = ((diValue >> i) & 1) == 1;
                                    }

                                    // UI 업데이트 - btnIn은 8개만
                                    this.BeginInvoke(new MethodInvoker(() =>
                                    {
                                        for (int i = 0; i < btnIn.Length; i++)
                                        {
                                            if (IO.IN[i])
                                            {
                                                btnIn[i].BackColor = pColor.Theme.LightRed;
                                                btnIn[i].ForeColor = System.Drawing.Color.Black;
                                            }
                                            else
                                            {
                                                btnIn[i].BackColor = pColor.Theme.DeepRed;
                                                btnIn[i].ForeColor = System.Drawing.Color.White;
                                            }
                                        }
                                    }));

                                    // AI 파싱 (Little Endian)
                                    ushort ai0 = (ushort)(buffer[3] | (buffer[4] << 8));
                                    ushort ai1 = (ushort)(buffer[5] | (buffer[6] << 8));
                                    ushort ai2 = (ushort)(buffer[7] | (buffer[8] << 8));
                                    ushort ai3 = (ushort)(buffer[9] | (buffer[10] << 8));

                                    // ADC 값 -> 실제 물리값 변환 (모드별 분기)
                                    if (GlobalValues.weldMode == "SPOT")
                                    {
                                        // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
                                        double ampRaw = (ai0 / 1023.0 * 3.0) * Amp.Tol;
                                        double tempRaw = ((ai1 / 1023.0 * 25.0) - 25.0) * Volt.Tol;
                                        double airRaw = (((ai2 / 1023.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;

                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
                                    }
                                    else
                                    {
                                        // CO2 모드: 전류/전압/유량
                                        double ampRaw = (ai0 / 1023.0 * 60.0) * Amp.Tol;
                                        double voltRaw = (ai1 / 1023.0 * 25.0) * Volt.Tol;
                                        double flowRaw = ((ai2 / 1023.0 * 12.5) - 12.5) * Flow.Tol;

                                        Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
                                        Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
                                        Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
                                    }

                                    labelAmp.Invoke(new MethodInvoker(() =>
                                    {
                                        labelAmp.Text = $"{Amp.Value.ToString("0.00")}";
                                        labelVolt.Text = $"{Volt.Value.ToString("0.00")}";
                                        labelFlow.Text = $"{Flow.Value.ToString("0.00")}";
                                    }));
                                }
                                else
                                {
                                    Logger.Log(LanguageManager.Get("log_checksum_error"));
                                }

                                readIndex = 0;  // 다음 패킷 대기
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    Logger.Log(LanguageManager.Get("log_v2_protocol_error", ex.Message));
                    readIndex = 0;  // 에러 시 초기화
                }
                Thread.Sleep(1);
            }
        }

        private void PortOpen(SerialPort tControl, string tPortNumber, int tBaudRate, string portLabelName)
        {
            try
            {
                if (tControl.IsOpen)
                    tControl.Close();

                tControl.PortName = tPortNumber;
                tControl.BaudRate = tBaudRate;
                tControl.DataBits = 8;
                tControl.Open();
                Logger.Log($"{portLabelName} ({tControl.PortName}): OK");

            }
            catch (Exception)
            {
                Logger.Log($"{portLabelName} ({tControl.PortName}): NG");

            }

        }

        // 복수 스캐너 포트 오픈
        private void OpenScannerPorts()
        {
            // 기존 포트 닫기
            foreach (var port in SerialScanners)
            {
                try { if (port.IsOpen) port.Close(); } catch { }
            }
            SerialScanners.Clear();

            if (string.IsNullOrEmpty(GlobalValues.scannerPorts)) return;

            var ports = GlobalValues.scannerPorts.Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (var portName in ports)
            {
                try
                {
                    var sp = new SerialPort
                    {
                        PortName = portName.Trim(),
                        BaudRate = 9600,
                        DataBits = 8,
                        Parity = Parity.None,
                        StopBits = StopBits.One
                    };
                    sp.DataReceived += Scanner_DataReceived;
                    sp.Open();
                    SerialScanners.Add(sp);
                    Logger.Log($"Scanner ({portName}): OK");
                }
                catch (Exception ex)
                {
                    Logger.Log($"Scanner ({portName}): NG - {ex.Message}");
                }
            }
        }

        // 복수 프린터 포트 오픈
        private void OpenPrinterPorts()
        {
            // 기존 포트 닫기
            foreach (var port in SerialPrinters)
            {
                try { if (port.IsOpen) port.Close(); } catch { }
            }
            SerialPrinters.Clear();

            if (string.IsNullOrEmpty(GlobalValues.printerPorts)) return;

            var ports = GlobalValues.printerPorts.Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (var portName in ports)
            {
                try
                {
                    var sp = new SerialPort
                    {
                        PortName = portName.Trim(),
                        BaudRate = 9600,
                        DataBits = 8,
                        Parity = Parity.None,
                        StopBits = StopBits.One
                    };
                    sp.Open();
                    SerialPrinters.Add(sp);
                    Logger.Log($"Printer ({portName}): OK");
                }
                catch (Exception ex)
                {
                    Logger.Log($"Printer ({portName}): NG - {ex.Message}");
                }
            }
        }

        // 스캐너 데이터 수신 이벤트 (모든 스캐너에서 공통 사용)
        private void Scanner_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            try
            {
                var sp = sender as SerialPort;
                if (sp == null || !sp.IsOpen) return;

                string data = sp.ReadExisting().Trim();
                if (string.IsNullOrEmpty(data)) return;

                // UI 스레드에서 처리
                this.BeginInvoke(new Action(() =>
                {
                    Logger.Log($"[{sp.PortName}] Scan: {data}");
                    ProcessScannerData(sp.PortName, data);
                }));
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Scanner_DataReceived error: {ex.Message}");
            }
        }

        // 스캐너 데이터 처리 (필요 시 구현)
        private void ProcessScannerData(string portName, string data)
        {
            // TODO: 스캔된 바코드 데이터 처리 로직
            // 예: 바코드로 JIG 매칭, 작업자 ID 확인 등
        }
    }
}

