## 2. CONTINUOUS READ REQUEST

### Frame Building

```csharp
public byte[] BuildReadContinuousRequest(
    ushort invokeId,
    string deviceType,     // "M", "L", "P", etc.
    uint startAddress,     // Starting address/index
    int count)             // Number of bytes/items to read
{
    List<byte> frame = new List<byte>();

    // Command (0x0054 = Read)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0054));

    // Data Type (0x0014 = Continuous)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0014));

    // Reserved (0x0000)
    frame.AddRange(new byte[2]);

    // Block Count (0x0001 for continuous)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0001));

    // Device Variable (variable length)
    // This depends on device type encoding - example shows simplified version
    byte[] deviceVarBytes = EncodeDeviceVariable(deviceType, startAddress);

    // Device Variable Length (2 bytes, little-endian)
    frame.AddRange(BitConverter.GetBytes((ushort)deviceVarBytes.Length));

    // Device Variable Bytes
    frame.AddRange(deviceVarBytes);

    // Count (number of bytes to read, 2 bytes little-endian)
    frame.AddRange(BitConverter.GetBytes((ushort)count));

    // Now build complete transmission with header
    var header = new FEnetHeader
    {
        CompanyID = Encoding.ASCII.GetBytes("LSIS-XGT"),
        SourceOfFrame = 0x33,  // Client
        InvokeID = invokeId,
        DataLength = (ushort)frame.Count,
        UseChecksum = true
    };

    var headerBytes = header.Serialize();
    return headerBytes.Concat(frame).ToArray();
}

// Example device variable encoding (simplified)
private byte[] EncodeDeviceVariable(string deviceType, uint address)
{
    List<byte> bytes = new List<byte>();

    // Device type identifier (example for M memory)
    switch (deviceType.ToUpper())
    {
        case "M":
            bytes.Add(0x4D); // 'M'
            break;
        case "L":
            bytes.Add(0x4C); // 'L'
            break;
        // ... etc for other types
    }

    // Address in little-endian format
    bytes.AddRange(BitConverter.GetBytes(address));

    return bytes.ToArray();
}
