## 5. CONTINUOUS WRITE RESPONSE PARSING

### Response Parsing

```csharp
public class WriteContinuousResponse
{
    public ushort InvokeID { get; set; }
    public bool IsSuccess { get; set; }
    public ushort ErrorCode { get; set; }

    public static WriteContinuousResponse Parse(byte[] buffer)
    {
        if (buffer.Length < 20)
            throw new ArgumentException("Buffer too small");

        var invokeId = BitConverter.ToUInt16(buffer, 14);

        var response = new WriteContinuousResponse { InvokeID = invokeId };

        int offset = 20;

        // Command (should be 0x0059 = 0x0058 + 1)
        ushort command = BitConverter.ToUInt16(buffer, offset);
        offset += 2;

        // DataType (should be 0x0014)
        offset += 2;

        // Reserved
        offset += 2;

        // ErrorStatus
        ushort errorStatus = BitConverter.ToUInt16(buffer, offset);
        offset += 2;

        if (errorStatus == 0xFFFF)
        {
            response.IsSuccess = false;
            response.ErrorCode = BitConverter.ToUInt16(buffer, offset);
        }
        else
        {
            response.IsSuccess = true;
            response.ErrorCode = 0x0000;
        }

        return response;
    }
}
```

