## 6. TCP CONNECTION MANAGEMENT

### Socket Handler

```csharp
public class FEnetTcpClient : IDisposable
{
    private TcpClient socket;
    private NetworkStream stream;
    private readonly string hostAddress;
    private readonly int port;
    private ushort nextInvokeId = 1;

    public FEnetTcpClient(string hostAddress, int port = 2004)
    {
        this.hostAddress = hostAddress;
        this.port = port;
    }

    public void Connect()
    {
        socket = new TcpClient();
        socket.Connect(hostAddress, port);
        stream = socket.GetStream();
    }

    public byte[] SendRequest(byte[] request, int timeoutMs = 3000)
    {
        if (!socket.Connected)
            throw new InvalidOperationException("Not connected");

        // Send request
        stream.Write(request, 0, request.Length);
        stream.Flush();

        // Receive response with timeout
        socket.ReceiveTimeout = timeoutMs;

        byte[] headerBuffer = new byte[20];
        int headerRead = stream.Read(headerBuffer, 0, 20);
        if (headerRead != 20)
            throw new IOException("Failed to read header");

        // Parse header to get data length
        ushort dataLength = BitConverter.ToUInt16(headerBuffer, 16);

        // Read data frame
        byte[] dataBuffer = new byte[dataLength];
        int dataRead = 0;
        while (dataRead < dataLength)
        {
            int read = stream.Read(dataBuffer, dataRead, dataLength - dataRead);
            if (read == 0)
                throw new IOException("Connection closed");
            dataRead += read;
        }

        // Combine header and data
        return headerBuffer.Concat(dataBuffer).ToArray();
    }

    public ushort GetNextInvokeId()
    {
        return nextInvokeId++;
    }

    public void Disconnect()
    {
        stream?.Dispose();
        socket?.Dispose();
    }

    public void Dispose()
    {
        Disconnect();
    }
}

// Usage
using (var client = new FEnetTcpClient("192.168.0.100"))
{
    client.Connect();

    // Build and send read request
    var requestBuilder = new FEnetRequestBuilder();
    byte[] readRequest = requestBuilder.BuildReadContinuousRequest(
        invokeId: client.GetNextInvokeId(),
        deviceType: "M",
        startAddress: 0,
        count: 10
    );

    byte[] responseBuffer = client.SendRequest(readRequest);
    var response = ReadContinuousResponse.Parse(responseBuffer);

    if (response.IsSuccess)
    {
        Console.WriteLine("Read successful");
        // Process response.Data
    }

    client.Disconnect();
}
```

