## 7. ERROR HANDLING AND VALIDATION

### Error Code Handler

```csharp
public enum FEnetErrorCode : ushort
{
    Unknown = 0x0000,
    OverRequestReadBlockCount = 0x0001,
    DeviceVariableTypeError = 0x0002,
    IllegalDeviceMemory = 0x0003,
    OutOfRangeDeviceVariable = 0x0004,
    OverDataLengthIndividual = 0x0005,
    OverDataLengthTotal = 0x0006,
    IllegalCompanyID = 0x0075,
    IllegalLength = 0x0076,
    ErrorChecksum = 0x0076,
    IllegalCommand = 0x0077
}

public class FEnetException : Exception
{
    public FEnetErrorCode ErrorCode { get; set; }

    public FEnetException(FEnetErrorCode code)
        : base(GetErrorMessage(code))
    {
        ErrorCode = code;
    }

    private static string GetErrorMessage(FEnetErrorCode code)
    {
        return code switch
        {
            FEnetErrorCode.IllegalDeviceMemory => "Unsupported device memory",
            FEnetErrorCode.OutOfRangeDeviceVariable => "Device address out of range",
            FEnetErrorCode.OverDataLengthIndividual => "Data length exceeds 1400 bytes",
            FEnetErrorCode.IllegalCommand => "Invalid command code",
            _ => $"FEnet error: 0x{(ushort)code:X4}"
        };
    }
}

// Usage
var response = ReadContinuousResponse.Parse(buffer);
if (!response.IsSuccess)
{
    throw new FEnetException((FEnetErrorCode)response.ErrorCode);
}
```

