175→        // 설치 폴더의 기본 DB를 사용자 데이터 폴더로 복사 (최초 1회)
176→        // 실행 파일이 C:\Program Files에 있어도 읽기만 하므로 관리자 권한 불필요
177→        private static void InitializeDatabase(string dbFileName)
178→        {
179→            string userDbPath = Path.Combine(GetDbPath(), dbFileName);
180→
181→            // 사용자 DB가 이미 있으면 복사 불필요
182→            if (File.Exists(userDbPath))
183→            {
184→                return;
185→            }
186→
187→            // 설치 폴더에서 기본 DB 찾기 (여러 위치 시도)
188→            string[] possiblePaths = new[]
189→            {
190→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", dbFileName),  // 설치본
191→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", dbFileName),  // 개발환경
192→                Path.Combine(Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location), "DB", dbFileName)
193→            };
194→
195→            foreach (string defaultDbPath in possiblePaths)
196→            {
197→                if (File.Exists(defaultDbPath))
198→                {
199→                    try
200→                    {
201→                        File.Copy(defaultDbPath, userDbPath, false);
202→                        System.Diagnostics.Debug.WriteLine($"DB 초기화 성공: {dbFileName} -> {userDbPath}");
203→                        return;
204→                    }
205→                    catch (Exception ex)
206→                    {
207→                        System.Diagnostics.Debug.WriteLine($"DB 복사 실패: {ex.Message}");
208→                        // 다음 경로 시도
209→                    }
210→                }
211→            }
212→
213→            // .mdb 파일이 없으면 기존 .accdb에서 데이터 마이그레이션 시도
214→            string accdbFileName = dbFileName.Replace(".mdb", ".accdb");
215→            string[] accdbPaths = new[]
216→            {
