218→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", accdbFileName),
219→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", accdbFileName)
220→            };
221→
222→            foreach (string accdbPath in accdbPaths)
223→            {
224→                if (File.Exists(accdbPath))
225→                {
226→                    System.Diagnostics.Debug.WriteLine($"기존 .accdb 발견, .mdb로 변환 시도: {accdbPath}");
227→                    // .accdb에서 .mdb로 직접 변환은 불가, 새 .mdb 생성 후 데이터 복사 필요
228→                    // 여기서는 새 .mdb 생성만 진행
229→                    break;
230→                }
231→            }
232→
233→            // 기본 DB가 없으면 새로 생성 (ADOX 사용)
234→            System.Diagnostics.Debug.WriteLine($"DB 파일 새로 생성: {userDbPath}");
235→            CreateNewMdbDatabase(userDbPath, dbFileName);
236→        }
