425→        private static bool _migrationChecked = false;
426→
427→        /// <summary>
428→        /// 레거시 DB에서 데이터 마이그레이션 (한 번만 실행)
429→        /// FtechWeldMonitor\DB\DataBase_Part.mdb → %LocalAppData%\WeldMonitor3\DB\
430→        /// 기존 데이터 유지, 레거시 DB에만 있는 Jig_ID만 추가
431→        /// </summary>
432→        private static void MigrateOldDatabase()
433→        {
434→            if (_migrationChecked) return;
435→            _migrationChecked = true;
436→
437→            // 레거시 DB 경로 검색 (FtechWeldMonitor 설치 폴더)
438→            string legacyDbPath = FindLegacyDatabase();
439→            if (string.IsNullOrEmpty(legacyDbPath))
440→            {
441→                System.Diagnostics.Debug.WriteLine("레거시 DB 파일 없음 - 마이그레이션 스킵");
442→                return;
443→            }
444→
445→            // 새 DB 경로와 동일하면 스킵
446→            string newDbPath = Path.Combine(GetDbPath(), "DataBase_Part.mdb");
447→            if (Path.GetFullPath(legacyDbPath).Equals(Path.GetFullPath(newDbPath), StringComparison.OrdinalIgnoreCase))
448→            {
449→                System.Diagnostics.Debug.WriteLine("레거시 DB와 새 DB가 동일 경로 - 마이그레이션 스킵");
450→                return;
451→            }
452→
453→            System.Diagnostics.Debug.WriteLine($"레거시 DB 발견: {legacyDbPath}");
454→
455→            try
456→            {
457→                string legacyConnString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + legacyDbPath;
458→                string newConnString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + newDbPath;
459→
460→                int jigCount = 0;
461→                int seqCount = 0;
462→
463→                using (var legacyConn = new OleDbConnection(legacyConnString))
464→                using (var newConn = new OleDbConnection(newConnString))
465→                {
466→                    legacyConn.Open();
467→                    newConn.Open();
468→
469→                    // 1. 새 DB의 기존 Jig_ID 목록 가져오기
470→                    var existingJigIds = new HashSet<string>();
471→                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", newConn))
472→                    using (var reader = cmd.ExecuteReader())
473→                    {
474→                        while (reader.Read())
475→                        {
476→                            existingJigIds.Add(reader["Jig_ID"].ToString());
477→                        }
478→                    }
479→
480→                    // 2. 레거시 DB에서 Table_Jig 읽기
481→                    var legacyJigs = new DataTable();
482→                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Jig", legacyConn))
483→                    {
484→                        adapter.Fill(legacyJigs);
485→                    }
486→
487→                    // 3. 레거시 DB에서 Table_Seq 읽기
488→                    var legacySeqs = new DataTable();
489→                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Seq", legacyConn))
490→                    {
491→                        adapter.Fill(legacySeqs);
492→                    }
493→
494→                    // 4. 새 DB에 없는 Jig만 추가
495→                    foreach (DataRow row in legacyJigs.Rows)
496→                    {
497→                        string jigId = row["Jig_ID"].ToString();
498→                        if (existingJigIds.Contains(jigId))
499→                            continue;  // 이미 있으면 스킵
500→
501→                        // Table_Jig INSERT
502→                        using (var cmd = new OleDbCommand(@"
503→                            INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable)
504→                            VALUES (?, ?, ?, ?, ?)", newConn))
505→                        {
506→                            cmd.Parameters.AddWithValue("?", jigId);
507→                            cmd.Parameters.AddWithValue("?", row["PartNo"] ?? "");
508→                            cmd.Parameters.AddWithValue("?", row["PartName"] ?? "");
509→                            cmd.Parameters.AddWithValue("?", row["ioOption"] ?? "");
510→                            cmd.Parameters.AddWithValue("?", row["Enable"] ?? true);
511→                            cmd.ExecuteNonQuery();
512→                            jigCount++;
513→                        }
514→
515→                        // 해당 Jig의 Table_Seq INSERT
516→                        var seqRows = legacySeqs.Select($"Jig_ID = '{jigId}'");
517→                        foreach (DataRow seqRow in seqRows)
518→                        {
519→                            using (var cmd = new OleDbCommand(@"
520→                                INSERT INTO Table_Seq (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min,
521→                                    Value3_Max, Value3_Min, Value1_Tol, Value2_Tol, Value3_Tol,
522→                                    Value1_Type, Value2_Type, Value3_Type, StartSector, EndSector, Pass,
523→                                    Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
524→                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", newConn))
525→                            {
526→                                cmd.Parameters.AddWithValue("?", jigId);
527→                                cmd.Parameters.AddWithValue("?", seqRow["Point_ID"] ?? "1");
528→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Max"] ?? 0);
529→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Min"] ?? 0);
530→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Max"] ?? 0);
531→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Min"] ?? 0);
532→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Max"] ?? 0);
533→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Min"] ?? 0);
534→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Tol"] ?? 1);
535→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Tol"] ?? 1);
536→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Tol"] ?? 1);
537→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Type"] ?? "Average");
538→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Type"] ?? "Average");
539→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Type"] ?? "Average");
540→                                cmd.Parameters.AddWithValue("?", seqRow["StartSector"] ?? 5);
541→                                cmd.Parameters.AddWithValue("?", seqRow["EndSector"] ?? 5);
542→                                cmd.Parameters.AddWithValue("?", seqRow["Pass"] ?? 0);
543→                                cmd.Parameters.AddWithValue("?", seqRow["Image_Coord_X"] ?? 0);
544→                                cmd.Parameters.AddWithValue("?", seqRow["Image_Coord_Y"] ?? 0);
545→                                cmd.Parameters.AddWithValue("?", seqRow["Image_Size_X"] ?? 50);
546→                                cmd.Parameters.AddWithValue("?", seqRow["Image_Size_Y"] ?? 50);
547→                                cmd.Parameters.AddWithValue("?", seqRow["graphWidth"] ?? 10);
548→                                cmd.ExecuteNonQuery();
549→                                seqCount++;
550→                            }
551→                        }
552→                    }
553→                }
554→
555→                System.Diagnostics.Debug.WriteLine($"레거시 DB 마이그레이션 완료: Jig {jigCount}개, Seq {seqCount}개 추가");
556→
557→                // 마이그레이션 완료 플래그 파일 생성 (재실행 방지)
558→                string migrationFlagPath = Path.Combine(GetDbPath(), ".migration_done");
559→                File.WriteAllText(migrationFlagPath, $"Migrated from: {legacyDbPath}\nDate: {DateTime.Now}");
560→                System.Diagnostics.Debug.WriteLine("마이그레이션 완료 플래그 생성");
561→            }
562→            catch (Exception ex)
563→            {
564→                System.Diagnostics.Debug.WriteLine($"레거시 DB 마이그레이션 오류: {ex.Message}");
565→            }
566→        }
