753→            string valueStr = ini.ReadValue(section, key);
754→
755→            if (string.IsNullOrWhiteSpace(valueStr))
756→            {
757→                // 값이 없으면 기본값 0 저장
758→                ini.WriteValue(section, key, "0");
759→                return 0.0;
760→            }
761→
762→            if (double.TryParse(valueStr, out double result))
763→            {
764→                return result;
765→            }
766→
767→            // 숫자 변환 실패 시도 → 0으로 저장
768→            //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
769→            ini.WriteValue(section, key, "0");
770→            return 0.0;
