    public static class JigDataManager
    {
        public static List<JigInfo> All = new List<JigInfo>();

        public static List<JigInfo> GetEnabledJigs()
        {
            return All.Where(jig =>
                jig.ParsedIoOptions.All(ch => IO.IN[ch])
            ).ToList();
        }

    }   
    public class JigInfo
    {
        public string PartNo;
        public string PartName;
        public string ioOption;
        public string Jig_ID;
        public string ImagePath;
        public string Code4M;
        public string EoNumber;
        public string BarcodeSizeOffset;
        public int graphWidth;
        public string ScanTarget;  // 스캔 타겟 (/ 구분자, 예: "ABC123/DEF456")

        /// <summary>
        /// ScanTarget을 / 구분자로 파싱하여 리스트로 반환
        /// </summary>
        public List<string> ParsedScanTargets
        {
            get
            {
                if (string.IsNullOrWhiteSpace(ScanTarget))
                    return new List<string>();

                return ScanTarget
                    .Split('/')
                    .Select(s => s.Trim())
                    .Where(s => !string.IsNullOrEmpty(s))
                    .ToList();
            }
        }
        public List<int> ParsedIoOptions
        {
            get
            {
                if (string.IsNullOrWhiteSpace(ioOption))
                    return new List<int>();

                return ioOption
                    .Split('/')
                    .Select(s => int.TryParse(s, out int val) ? val : -1)
                    .Where(i => i >= 0 && i < IO.IN.Length) // 유효한 채널만
                    .ToList();
            }
        }
    }
