using System;
using System.Net.Sockets;
using System.Text;

namespace WeldMonitor3
{
    /// <summary>
    /// LS Electric XGT FEnet TCP communication helper.
    /// Protocol: XGT Dedicated Protocol over TCP port 2004.
    /// Supports continuous block read/write for %MW (Memory Word) addresses.
    /// Reference: VagabondK.Protocols, LS Electric XGT FEnet Manual V2.30
    /// </summary>
    public class XgtFEnetHelper
    {
        private TcpClient _client;
        private NetworkStream _stream;
        private readonly object _lock = new object();
        private ushort _invokeId;

        // Protocol constants
        private static readonly byte[] COMPANY_ID = Encoding.ASCII.GetBytes("LSIS-XGT");
        private const byte CPU_XGK = 0xA0;
        private const byte SRC_CLIENT = 0x33;
        private const ushort CMD_READ = 0x0054;
        private const ushort CMD_WRITE = 0x0058;
        private const ushort CMD_READ_RSP = 0x0055;
        private const ushort CMD_WRITE_RSP = 0x0059;
        private const ushort DTYPE_CONTINUOUS = 0x0014;
        private const int HEADER_SIZE = 20;
        public const int DEFAULT_PORT = 2004;
        private const int TIMEOUT_MS = 3000;

        public bool IsConnected => _client?.Connected ?? false;
        public string LastError { get; private set; }

        public bool Connect(string ip, int port = DEFAULT_PORT)
        {
            try
            {
                Disconnect();
                _client = new TcpClient();
                _client.SendTimeout = TIMEOUT_MS;
                _client.ReceiveTimeout = TIMEOUT_MS;
                _client.Connect(ip, port);
                _stream = _client.GetStream();
                _invokeId = 0;
                LastError = null;
                return true;
            }
            catch (Exception ex)
            {
                LastError = ex.Message;
                return false;
            }
        }

        public void Disconnect()
        {
            try { _stream?.Close(); } catch { }
            try { _client?.Close(); } catch { }
            _stream = null;
            _client = null;
        }

        /// <summary>
        /// Read continuous block of words from PLC.
        /// </summary>
        /// <param name="startAddress">Start address, e.g. "%MW100"</param>
        /// <param name="wordCount">Number of words to read (max 200)</param>
        /// <param name="buffer">Output buffer (int array)</param>
        /// <param name="bufferOffset">Offset in output buffer</param>
        public bool ReadWords(string startAddress, int wordCount, int[] buffer, int bufferOffset = 0)
        {
            if (!IsConnected) return false;
            lock (_lock)
            {
                try
                {
                    byte[] nameBytes = Encoding.ASCII.GetBytes(startAddress);
                    int byteCount = wordCount * 2;

                    // Data frame: cmd(2)+dtype(2)+rsv(2)+blockCnt(2)+nameLen(2)+name(N)+dataCnt(2)
                    int dataLen = 12 + nameBytes.Length;
                    byte[] packet = new byte[HEADER_SIZE + dataLen];

                    BuildHeader(packet, (ushort)dataLen);
                    int pos = HEADER_SIZE;
                    WriteU16(packet, ref pos, CMD_READ);
                    WriteU16(packet, ref pos, DTYPE_CONTINUOUS);
                    WriteU16(packet, ref pos, 0); // reserved
                    WriteU16(packet, ref pos, 1); // block count
                    WriteU16(packet, ref pos, (ushort)nameBytes.Length);
                    Array.Copy(nameBytes, 0, packet, pos, nameBytes.Length); pos += nameBytes.Length;
                    WriteU16(packet, ref pos, (ushort)byteCount);

                    _stream.Write(packet, 0, packet.Length);

                    // Receive response
                    byte[] rspHdr = ReadExact(HEADER_SIZE);
                    if (rspHdr == null) return false;

                    int rspDataLen = BitConverter.ToUInt16(rspHdr, 18);
                    byte[] rspData = ReadExact(rspDataLen);
                    if (rspData == null) return false;

                    // Verify: cmd(2)+dtype(2)+rsv(2)+errStatus(2)+blockCnt(2)+dataCnt(2)+data
                    if (rspData.Length < 12) { LastError = "Response too short"; return false; }

                    ushort rspCmd = BitConverter.ToUInt16(rspData, 0);
                    if (rspCmd != CMD_READ_RSP) { LastError = $"Bad cmd: 0x{rspCmd:X4}"; return false; }

                    ushort errStatus = BitConverter.ToUInt16(rspData, 6);
                    if (errStatus != 0) { LastError = $"PLC error: 0x{errStatus:X4}"; return false; }

                    int dataStart = 10; // after cmd+dtype+rsv+err+blockCnt
                    ushort rspByteCount = BitConverter.ToUInt16(rspData, dataStart);
                    dataStart += 2;

                    int wordsAvailable = Math.Min(wordCount, rspByteCount / 2);
                    for (int i = 0; i < wordsAvailable; i++)
                    {
                        buffer[bufferOffset + i] = BitConverter.ToUInt16(rspData, dataStart + i * 2);
                    }
                    return true;
                }
                catch (Exception ex)
                {
                    LastError = ex.Message;
                    Disconnect();
                    return false;
                }
            }
        }

        /// <summary>
        /// Write continuous block of words to PLC.
        /// </summary>
        public bool WriteWords(string startAddress, int wordCount, int[] data, int dataOffset = 0)
        {
            if (!IsConnected) return false;
            lock (_lock)
            {
                try
                {
                    byte[] nameBytes = Encoding.ASCII.GetBytes(startAddress);
                    int byteCount = wordCount * 2;

                    // Data frame: cmd(2)+dtype(2)+rsv(2)+blockCnt(2)+nameLen(2)+name(N)+dataCnt(2)+data(byteCount)
                    int dataLen = 12 + nameBytes.Length + byteCount;
                    byte[] packet = new byte[HEADER_SIZE + dataLen];

                    BuildHeader(packet, (ushort)dataLen);
                    int pos = HEADER_SIZE;
                    WriteU16(packet, ref pos, CMD_WRITE);
                    WriteU16(packet, ref pos, DTYPE_CONTINUOUS);
                    WriteU16(packet, ref pos, 0); // reserved
                    WriteU16(packet, ref pos, 1); // block count
                    WriteU16(packet, ref pos, (ushort)nameBytes.Length);
                    Array.Copy(nameBytes, 0, packet, pos, nameBytes.Length); pos += nameBytes.Length;
                    WriteU16(packet, ref pos, (ushort)byteCount);

                    // Write word data as little-endian bytes
                    for (int i = 0; i < wordCount; i++)
                    {
                        packet[pos++] = (byte)(data[dataOffset + i] & 0xFF);
                        packet[pos++] = (byte)((data[dataOffset + i] >> 8) & 0xFF);
                    }

                    _stream.Write(packet, 0, packet.Length);

                    // Receive response
                    byte[] rspHdr = ReadExact(HEADER_SIZE);
                    if (rspHdr == null) return false;

                    int rspDataLen = BitConverter.ToUInt16(rspHdr, 18);
                    byte[] rspData = ReadExact(rspDataLen);
                    if (rspData == null) return false;

                    if (rspData.Length < 8) { LastError = "Response too short"; return false; }

                    ushort rspCmd = BitConverter.ToUInt16(rspData, 0);
                    if (rspCmd != CMD_WRITE_RSP) { LastError = $"Bad cmd: 0x{rspCmd:X4}"; return false; }

                    ushort errStatus = BitConverter.ToUInt16(rspData, 6);
                    if (errStatus != 0) { LastError = $"PLC error: 0x{errStatus:X4}"; return false; }

                    return true;
                }
                catch (Exception ex)
                {
                    LastError = ex.Message;
                    Disconnect();
                    return false;
                }
            }
        }

        private void BuildHeader(byte[] packet, ushort dataLength)
        {
            Array.Copy(COMPANY_ID, 0, packet, 0, 8);
            // [8-13] reserved + PLC info (zeros)
            packet[14] = CPU_XGK;
            packet[15] = SRC_CLIENT;
            ushort id = ++_invokeId;
            packet[16] = (byte)(id & 0xFF);
            packet[17] = (byte)((id >> 8) & 0xFF);
            packet[18] = (byte)(dataLength & 0xFF);
            packet[19] = (byte)((dataLength >> 8) & 0xFF);
        }

        private byte[] ReadExact(int count)
        {
            byte[] buf = new byte[count];
            int offset = 0;
            while (offset < count)
            {
                int read = _stream.Read(buf, offset, count - offset);
                if (read <= 0) { LastError = "Connection closed"; return null; }
                offset += read;
            }
            return buf;
        }

        private static void WriteU16(byte[] buf, ref int pos, ushort value)
        {
            buf[pos++] = (byte)(value & 0xFF);
            buf[pos++] = (byte)((value >> 8) & 0xFF);
        }
    }
}

