using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using System.Windows.Forms;
using System.Data;
using System.Data.OleDb;
using System.Diagnostics;
using System.IO;
using System.Media;
using ScottPlot;
using System.Drawing;

namespace WeldMonitor3
{
    public class FilteredValue
    {
        private double filtered = 0;
        private readonly double alpha;

        public FilteredValue(double alpha)
        {
            this.alpha = alpha;
        }

        public double Update(double newValue)
        {
            filtered = alpha * newValue + (1 - alpha) * filtered;
            return filtered;
        }
    }
    public class pColor
    {
        // 다크테마 색상으로 변경
        public System.Drawing.Color backColor = ColorTranslator.FromHtml("#2b2b2b");      // 중간 배경
        public System.Drawing.Color panelColor = ColorTranslator.FromHtml("#1e1e1e");     // 어두운 배경
        public System.Drawing.Color buttonColor = ColorTranslator.FromHtml("#3c3c3c");    // 버튼 배경
        public System.Drawing.Color buttonHover = ColorTranslator.FromHtml("#4a4a4a");    // 버튼 호버
        public System.Drawing.Color buttonText = ColorTranslator.FromHtml("#ffffff");     // 버튼 텍스트
        public System.Drawing.Color logText = ColorTranslator.FromHtml("#ffffff");        // 로그 텍스트
        public System.Drawing.Color LightRed = System.Drawing.Color.FromArgb(229, 115, 115);
        public System.Drawing.Color LightGreen = System.Drawing.Color.FromArgb(129, 199, 132);
        public System.Drawing.Color DeepRed = System.Drawing.Color.FromArgb(127, 29, 29);
        public System.Drawing.Color DeepGreen = System.Drawing.Color.FromArgb(27, 67, 50);
        public static pColor Theme { get; } = new pColor();
    }    
    public static class JigDataManager
    {
        public static List<JigInfo> All = new List<JigInfo>();

        public static List<JigInfo> GetEnabledJigs()
        {
            return All.Where(jig =>
                jig.ParsedIoOptions.All(ch => IO.IN[ch])
            ).ToList();
        }

    }   
    public class JigInfo
    {
        public string PartNo;
        public string PartName;
        public string ioOption;
        public string Jig_ID;
        public string ImagePath;
        public string Code4M;
        public string EoNumber;
        public string BarcodeSizeOffset;
        public int graphWidth;
        public string ScanTarget;  // 스캔 타겟 (/ 구분자, 예: "ABC123/DEF456")

        /// <summary>
        /// ScanTarget을 / 구분자로 파싱하여 리스트로 반환
        /// </summary>
        public List<string> ParsedScanTargets
        {
            get
            {
                if (string.IsNullOrWhiteSpace(ScanTarget))
                    return new List<string>();

                return ScanTarget
                    .Split('/')
                    .Select(s => s.Trim())
                    .Where(s => !string.IsNullOrEmpty(s))
                    .ToList();
            }
        }
        public List<int> ParsedIoOptions
        {
            get
            {
                if (string.IsNullOrWhiteSpace(ioOption))
                    return new List<int>();

                return ioOption
                    .Split('/')
                    .Select(s => int.TryParse(s, out int val) ? val : -1)
                    .Where(i => i >= 0 && i < IO.IN.Length) // 유효한 채널만
                    .ToList();
            }
        }
    }
    public static class PointDataManager
    {
        public static Dictionary<string, PointData> All = new Dictionary<string, PointData>();
    }
