        // 사용자 데이터 폴더 경로 (관리자 권한 불필요)
        private static string GetUserDataPath()
        {
            string userDataPath = Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                "WeldMonitor3");

            // 폴더가 없으면 생성
            if (!Directory.Exists(userDataPath))
            {
                Directory.CreateDirectory(userDataPath);
            }

            return userDataPath;
        }

        // DB 폴더 경로
        public static string GetDbPath()
        {
            string dbPath = Path.Combine(GetUserDataPath(), "DB");
            if (!Directory.Exists(dbPath))
            {
                Directory.CreateDirectory(dbPath);
            }
            return dbPath;
        }

        // 설치 폴더의 기본 DB를 사용자 데이터 폴더로 복사 (최초 1회)
        // 실행 파일이 C:\Program Files에 있어도 읽기만 하므로 관리자 권한 불필요
        private static void InitializeDatabase(string dbFileName)
        {
            string userDbPath = Path.Combine(GetDbPath(), dbFileName);

            // 사용자 DB가 이미 있으면 복사 불필요
            if (File.Exists(userDbPath))
            {
                return;
            }

            // 설치 폴더에서 기본 DB 찾기 (여러 위치 시도)
            string[] possiblePaths = new[]
            {
                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", dbFileName),  // 설치본
                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", dbFileName),  // 개발환경
                Path.Combine(Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location), "DB", dbFileName)
            };

            foreach (string defaultDbPath in possiblePaths)
            {
                if (File.Exists(defaultDbPath))
                {
                    try
                    {
                        File.Copy(defaultDbPath, userDbPath, false);
                        System.Diagnostics.Debug.WriteLine($"DB 초기화 성공: {dbFileName} -> {userDbPath}");
                        return;
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"DB 복사 실패: {ex.Message}");
                        // 다음 경로 시도
                    }
                }
            }

            // .mdb 파일이 없으면 기존 .accdb에서 데이터 마이그레이션 시도
            string accdbFileName = dbFileName.Replace(".mdb", ".accdb");
            string[] accdbPaths = new[]
            {
                Path.Combine(GetDbPath(), accdbFileName),  // 사용자 폴더의 기존 accdb
                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", accdbFileName),
                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", accdbFileName)
            };

            foreach (string accdbPath in accdbPaths)
            {
                if (File.Exists(accdbPath))
                {
                    System.Diagnostics.Debug.WriteLine($"기존 .accdb 발견, .mdb로 변환 시도: {accdbPath}");
                    // .accdb에서 .mdb로 직접 변환은 불가, 새 .mdb 생성 후 데이터 복사 필요
                    // 여기서는 새 .mdb 생성만 진행
                    break;
                }
            }

            // 기본 DB가 없으면 새로 생성 (ADOX 사용)
            System.Diagnostics.Debug.WriteLine($"DB 파일 새로 생성: {userDbPath}");
            CreateNewMdbDatabase(userDbPath, dbFileName);
        }

        // ADOX를 사용하여 새 .mdb 파일 생성
        private static void CreateNewMdbDatabase(string dbPath, string dbFileName)
        {
            try
            {
                // ADOX Catalog으로 .mdb 파일 생성
                var cat = new ADOX.Catalog();
                string connString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + dbPath;
                cat.Create(connString);

                // 연결 해제
                System.Runtime.InteropServices.Marshal.ReleaseComObject(cat);
                cat = null;

                System.Diagnostics.Debug.WriteLine($"빈 MDB 파일 생성 완료: {dbPath}");

                // 테이블 생성
                using (var conn = new OleDbConnection(connString))
                {
                    conn.Open();

                    if (dbFileName.Contains("Part"))
                    {
                        // Table_Jig 생성
                        string createJigTable = @"CREATE TABLE Table_Jig (
                            ID COUNTER PRIMARY KEY,
                            Jig_ID TEXT(50),
                            PartNo TEXT(100),
                            PartName TEXT(100),
                            ioOption TEXT(50),
                            Enable YESNO,
                            Code4M TEXT(50),
                            EoNumber TEXT(50),
                            BarcodeSizeOffset TEXT(50),
                            scanTarget TEXT(255),
                            ImagePath TEXT(255)
                        )";
                        using (var cmd = new OleDbCommand(createJigTable, conn))
                        {
                            cmd.ExecuteNonQuery();
                        }
                        System.Diagnostics.Debug.WriteLine("Table_Jig 테이블 생성 완료");

                        // Table_Seq 생성 (포인트 설정 테이블)
                        string createSeqTable = @"CREATE TABLE Table_Seq (
                            ID COUNTER PRIMARY KEY,
                            Jig_ID TEXT(50),
                            Point_ID INTEGER,
                            Value1_Max DOUBLE,
                            Value1_Min DOUBLE,
                            Value2_Max DOUBLE,
                            Value2_Min DOUBLE,
                            Value3_Max DOUBLE,
                            Value3_Min DOUBLE,
                            Value1_Tol DOUBLE,
                            Value2_Tol DOUBLE,
                            Value3_Tol DOUBLE,
                            Value1_Type TEXT(20),
                            Value2_Type TEXT(20),
                            Value3_Type TEXT(20),
                            StartSector INTEGER,
                            EndSector INTEGER,
                            Pass INTEGER,
                            Image_Coord_X INTEGER,
                            Image_Coord_Y INTEGER,
                            Image_Size_X INTEGER,
                            Image_Size_Y INTEGER,
                            graphWidth INTEGER
                        )";
                        using (var cmd = new OleDbCommand(createSeqTable, conn))
                        {
                            cmd.ExecuteNonQuery();
                        }
                        System.Diagnostics.Debug.WriteLine("Table_Seq 테이블 생성 완료");

                        // 기본 JIG 128개 생성
                        for (int i = 1; i <= 128; i++)
                        {
                            string jigId = i.ToString();
                            string ioOption;
                            if (i <= 64)
                            {
                                var channels = new List<string>();
                                for (int bit = 0; bit < 6; bit++)
                                    if ((i & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                                ioOption = string.Join("/", channels);
                            }
                            else
                                ioOption = "";  // 65~128: 미사용
                            string insertJig = $"INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable) VALUES ('{jigId}', '', '', '{ioOption}', True)";
                            using (var cmd = new OleDbCommand(insertJig, conn))
                            {
                                cmd.ExecuteNonQuery();
                            }
                        }
                        System.Diagnostics.Debug.WriteLine("기본 JIG 128개 생성 완료");
                    }
                    else if (dbFileName.Contains("Record"))
                    {
                        // Table_Record 생성
                        string createRecordTable = @"CREATE TABLE Table_Record (
                            ID COUNTER PRIMARY KEY,
                            JIG_ID TEXT(50),
                            POINT_ID INTEGER,
                            DateTime DATETIME,
                            AMP_AVG DOUBLE,
                            AMP_MAX DOUBLE,
                            AMP_MIN DOUBLE,
                            VOLT_AVG DOUBLE,
                            VOLT_MAX DOUBLE,
                            VOLT_MIN DOUBLE,
                            FLOW_AVG DOUBLE,
                            FLOW_MAX DOUBLE,
                            FLOW_MIN DOUBLE,
                            TIME_ELAPSED DOUBLE,
                            Result TEXT(10)
                        )";
                        using (var cmd = new OleDbCommand(createRecordTable, conn))
                        {
                            cmd.ExecuteNonQuery();
                        }
                        System.Diagnostics.Debug.WriteLine("Table_Record 테이블 생성 완료");
                    }

                    conn.Close();
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"MDB 파일 생성 실패: {ex.Message}");
            }
        }

        /// <summary>
        /// Table_Jig에 Jig_ID 1~128이 없으면 추가. comboBoxJigID에 128까지 표시.
        /// </summary>
        private static void EnsureJigCount128(string connString)
        {
            try
            {
                using (var conn = new OleDbConnection(connString))
                {
                    conn.Open();
                    var existing = new HashSet<string>();
                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", conn))
                    using (var reader = cmd.ExecuteReader())
                    {
                        while (reader.Read())
                        {
                            string id = reader["Jig_ID"].ToString();
                            if (!string.IsNullOrEmpty(id))
                                existing.Add(id);
                        }
                    }
                    for (int i = 1; i <= 128; i++)
                    {
                        string jigId = i.ToString();
                        if (existing.Contains(jigId)) continue;
                        string ioOption;
                        if (i <= 64)
                        {
                            var channels = new List<string>();
                            for (int bit = 0; bit < 6; bit++)
                                if ((i & (1 << bit)) != 0) channels.Add((bit + 1).ToString());
                            ioOption = string.Join("/", channels);
                        }
                        else
                            ioOption = "";
                        using (var cmd = new OleDbCommand("INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable) VALUES (?, ?, ?, ?, ?)", conn))
                        {
                            cmd.Parameters.AddWithValue("?", jigId);
                            cmd.Parameters.AddWithValue("?", "");
                            cmd.Parameters.AddWithValue("?", "");
                            cmd.Parameters.AddWithValue("?", ioOption);
                            cmd.Parameters.AddWithValue("?", true);
                            cmd.ExecuteNonQuery();
                        }
                        existing.Add(jigId);
                    }
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"EnsureJigCount128 실패: {ex.Message}");
            }
        }

        private static bool _migrationChecked = false;

        /// <summary>
        /// 레거시 DB에서 데이터 마이그레이션 (한 번만 실행)
        /// FtechWeldMonitor\DB\DataBase_Part.mdb → %LocalAppData%\WeldMonitor3\DB\
        /// 기존 데이터 유지, 레거시 DB에만 있는 Jig_ID만 추가
        /// </summary>
        private static void MigrateOldDatabase()
        {
            if (_migrationChecked) return;
            _migrationChecked = true;

            // 레거시 DB 경로 검색 (FtechWeldMonitor 설치 폴더)
            string legacyDbPath = FindLegacyDatabase();
            if (string.IsNullOrEmpty(legacyDbPath))
            {
                System.Diagnostics.Debug.WriteLine("레거시 DB 파일 없음 - 마이그레이션 스킵");
                return;
            }

            // 새 DB 경로와 동일하면 스킵
            string newDbPath = Path.Combine(GetDbPath(), "DataBase_Part.mdb");
            if (Path.GetFullPath(legacyDbPath).Equals(Path.GetFullPath(newDbPath), StringComparison.OrdinalIgnoreCase))
            {
                System.Diagnostics.Debug.WriteLine("레거시 DB와 새 DB가 동일 경로 - 마이그레이션 스킵");
                return;
            }

            System.Diagnostics.Debug.WriteLine($"레거시 DB 발견: {legacyDbPath}");

            try
            {
                string legacyConnString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + legacyDbPath;
                string newConnString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + newDbPath;

                int jigCount = 0;
                int seqCount = 0;

                using (var legacyConn = new OleDbConnection(legacyConnString))
                using (var newConn = new OleDbConnection(newConnString))
                {
                    legacyConn.Open();
                    newConn.Open();

                    // 1. 새 DB의 기존 Jig_ID 목록 가져오기
                    var existingJigIds = new HashSet<string>();
                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", newConn))
                    using (var reader = cmd.ExecuteReader())
                    {
                        while (reader.Read())
                        {
                            existingJigIds.Add(reader["Jig_ID"].ToString());
                        }
                    }

                    // 2. 레거시 DB에서 Table_Jig 읽기
                    var legacyJigs = new DataTable();
                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Jig", legacyConn))
                    {
                        adapter.Fill(legacyJigs);
                    }

                    // 3. 레거시 DB에서 Table_Seq 읽기
                    var legacySeqs = new DataTable();
                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Seq", legacyConn))
                    {
                        adapter.Fill(legacySeqs);
                    }

                    // 4. 새 DB에 없는 Jig만 추가
                    foreach (DataRow row in legacyJigs.Rows)
                    {
                        string jigId = row["Jig_ID"].ToString();
                        if (existingJigIds.Contains(jigId))
                            continue;  // 이미 있으면 스킵

                        // Table_Jig INSERT
                        using (var cmd = new OleDbCommand(@"
                            INSERT INTO Table_Jig (Jig_ID, PartNo, PartName, ioOption, Enable)
                            VALUES (?, ?, ?, ?, ?)", newConn))
                        {
                            cmd.Parameters.AddWithValue("?", jigId);
                            cmd.Parameters.AddWithValue("?", row["PartNo"] ?? "");
                            cmd.Parameters.AddWithValue("?", row["PartName"] ?? "");
                            cmd.Parameters.AddWithValue("?", row["ioOption"] ?? "");
                            cmd.Parameters.AddWithValue("?", row["Enable"] ?? true);
                            cmd.ExecuteNonQuery();
                            jigCount++;
                        }

                        // 해당 Jig의 Table_Seq INSERT
                        var seqRows = legacySeqs.Select($"Jig_ID = '{jigId}'");
                        foreach (DataRow seqRow in seqRows)
                        {
                            using (var cmd = new OleDbCommand(@"
                                INSERT INTO Table_Seq (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min,
                                    Value3_Max, Value3_Min, Value1_Tol, Value2_Tol, Value3_Tol,
                                    Value1_Type, Value2_Type, Value3_Type, StartSector, EndSector, Pass,
                                    Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", newConn))
                            {
                                cmd.Parameters.AddWithValue("?", jigId);
                                cmd.Parameters.AddWithValue("?", seqRow["Point_ID"] ?? "1");
                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Max"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Min"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Max"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Min"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Max"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Min"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Tol"] ?? 1);
                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Tol"] ?? 1);
                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Tol"] ?? 1);
                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Type"] ?? "Average");
                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Type"] ?? "Average");
                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Type"] ?? "Average");
                                cmd.Parameters.AddWithValue("?", seqRow["StartSector"] ?? 5);
                                cmd.Parameters.AddWithValue("?", seqRow["EndSector"] ?? 5);
                                cmd.Parameters.AddWithValue("?", seqRow["Pass"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Image_Coord_X"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Image_Coord_Y"] ?? 0);
                                cmd.Parameters.AddWithValue("?", seqRow["Image_Size_X"] ?? 50);
                                cmd.Parameters.AddWithValue("?", seqRow["Image_Size_Y"] ?? 50);
                                cmd.Parameters.AddWithValue("?", seqRow["graphWidth"] ?? 10);
                                cmd.ExecuteNonQuery();
                                seqCount++;
                            }
                        }
                    }
                }

                System.Diagnostics.Debug.WriteLine($"레거시 DB 마이그레이션 완료: Jig {jigCount}개, Seq {seqCount}개 추가");

                // 마이그레이션 완료 플래그 파일 생성 (재실행 방지)
                string migrationFlagPath = Path.Combine(GetDbPath(), ".migration_done");
                File.WriteAllText(migrationFlagPath, $"Migrated from: {legacyDbPath}\nDate: {DateTime.Now}");
                System.Diagnostics.Debug.WriteLine("마이그레이션 완료 플래그 생성");
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"레거시 DB 마이그레이션 오류: {ex.Message}");
            }
        }

        /// <summary>
        /// 레거시 FtechWeldMonitor DB 경로 검색
        /// Program Files에서 "ftech"로 시작하는 폴더 검색
        /// </summary>
        private static string FindLegacyDatabase()
        {
            // 마이그레이션 완료 플래그 확인
            string migrationFlagPath = Path.Combine(GetDbPath(), ".migration_done");
            if (File.Exists(migrationFlagPath))
            {
                System.Diagnostics.Debug.WriteLine("이미 마이그레이션 완료됨");
                return null;
            }

            // 검색할 Program Files 경로
            var programFilesPaths = new List<string>();

            foreach (var drive in DriveInfo.GetDrives())
            {
                if (drive.DriveType != DriveType.Fixed) continue;

                string root = drive.Name;
                programFilesPaths.Add(Path.Combine(root, "Program Files"));
                programFilesPaths.Add(Path.Combine(root, "Program Files (x86)"));
            }

            // Program Files에서 "ftech"로 시작하는 폴더 검색
            foreach (string programFiles in programFilesPaths)
            {
                if (!Directory.Exists(programFiles)) continue;

                try
                {
                    var ftechFolders = Directory.GetDirectories(programFiles, "ftech*", SearchOption.TopDirectoryOnly);
                    foreach (string ftechFolder in ftechFolders)
                    {
                        string dbPath = Path.Combine(ftechFolder, "DB", "DataBase_Part.mdb");
                        if (File.Exists(dbPath))
                        {
                            return dbPath;
                        }
                    }
                }
                catch (UnauthorizedAccessException)
                {
                    // 권한 없는 폴더 무시
                }
            }

            // 현재 실행 파일 경로의 DB 폴더도 확인
            string localDbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", "DataBase_Part.mdb");
            if (File.Exists(localDbPath))
            {
                return localDbPath;
            }

            return null;
        }

        // DB 스키마 업데이트 - 누락된 컬럼 자동 추가
        private static void EnsureDbSchema(string connString)
        {
            try
            {
                using (var conn = new System.Data.OleDb.OleDbConnection(connString))
                {
                    conn.Open();

                    // Table_Jig에 scanTarget 컬럼 확인 및 추가
                    if (!ColumnExists(conn, "Table_Jig", "scanTarget"))
                    {
                        using (var cmd = new System.Data.OleDb.OleDbCommand("ALTER TABLE Table_Jig ADD COLUMN scanTarget TEXT(255)", conn))
                        {
                            cmd.ExecuteNonQuery();
                            System.Diagnostics.Debug.WriteLine("Table_Jig에 scanTarget 컬럼 추가됨");
                        }
                    }

                    conn.Close();
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"DB 스키마 업데이트 실패: {ex.Message}");
            }
        }

        // 컬럼 존재 여부 확인
        private static bool ColumnExists(System.Data.OleDb.OleDbConnection conn, string tableName, string columnName)
        {
            try
            {
                var schema = conn.GetSchema("Columns", new[] { null, null, tableName, columnName });
                return schema.Rows.Count > 0;
            }
            catch
            {
                return false;
            }
        }

        private static bool _schemaChecked = false;
        private static readonly object _schemaLock = new object();

        public static string gConString_Part
        {
            get
            {
                InitializeDatabase("DataBase_Part.mdb");
                string dbPath = Path.Combine(GetDbPath(), "DataBase_Part.mdb");
                string connString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + dbPath;

                // 최초 1회만 스키마 체크 및 마이그레이션 (다중 스레드 접근 시 한 번만 실행)
                if (!_schemaChecked)
                {
                    lock (_schemaLock)
                    {
                        if (!_schemaChecked)
                        {
                            EnsureDbSchema(connString);
                            MigrateOldDatabase();  // 레거시 DB 병합
                            EnsureJigCount128(connString);  // Table_Jig에 1~128번 없으면 추가 (comboBoxJigID에 128까지 표시)
                            _schemaChecked = true;
                        }
                    }
                }

                return connString;
            }
        }

