        // 용접 모드 설정 (CO2 / SPOT)
        public static string weldMode = "CO2";  // "CO2" or "SPOT"
        // SPOT 모드 전용: 용접 감지 임계값 (kA)
        public static double spotWeldThreshold = 2.0;
        // SPOT 모드 전용: Volt/Flow 사용 여부
        public static bool spotUseVolt = true;
        public static bool spotUseFlow = true;

        public static double TryGetDouble(IniFile ini, string section, string key, double defaultValue = 0.0)
        {
            string valueStr = ini.ReadValue(section, key);

            if (string.IsNullOrWhiteSpace(valueStr))
            {
                // 값이 없으면 기본값 0 저장
                ini.WriteValue(section, key, "0");
                return 0.0;
            }

            if (double.TryParse(valueStr, out double result))
            {
                return result;
            }

            // 숫자 변환 실패 시도 → 0으로 저장
            //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
            ini.WriteValue(section, key, "0");
            return 0.0;
        }
        public static int TryGetInt(IniFile ini, string section, string key, int defaultValue = 0)
        {
            string valueStr = ini.ReadValue(section, key);

            if (string.IsNullOrWhiteSpace(valueStr))
            {
                // 값이 없으면 기본값 저장
                ini.WriteValue(section, key, defaultValue.ToString());
                return defaultValue;
            }

            if (int.TryParse(valueStr, out int result))
            {
                return result;
            }

            // 숫자 변환 실패 → 기본값으로 저장
            ini.WriteValue(section, key, defaultValue.ToString());
            return defaultValue;
        }
        public static void LoadSettingsFromIni()
        {
            string newConfigPath = GetConfigPath();

            // 사용자 폴더에 config.ini가 없으면 설치 폴더에서 복사
            if (!File.Exists(newConfigPath))
            {
                // 여러 위치에서 기본 config.ini 찾기
                string[] possiblePaths = new[]
                {
                    Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "config.ini"),  // 설치본
                    Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "config.ini")  // 개발환경/기존
                };

                foreach (string srcPath in possiblePaths)
                {
                    if (File.Exists(srcPath))
                    {
                        try
                        {
                            // 사용자 폴더 생성
                            string userDir = Path.GetDirectoryName(newConfigPath);
                            if (!Directory.Exists(userDir))
                                Directory.CreateDirectory(userDir);

                            File.Copy(srcPath, newConfigPath, false);
                            System.Diagnostics.Debug.WriteLine($"Config 초기화 성공: {srcPath} -> {newConfigPath}");
                            break;
                        }
                        catch (Exception ex)
                        {
                            System.Diagnostics.Debug.WriteLine($"Config 복사 실패: {ex.Message}");
                        }
                    }
                }
            }

            IniFile ini = new IniFile(newConfigPath);

            strPassWord = ReadString(ini, "System", "PassWord");
            strTitle = ReadString(ini, "System", "Title");
            scannerPort = ReadString(ini, "System", "scannerPort");
            printerPort = ReadString(ini, "System", "printerPort");
            scannerPorts = ReadString(ini, "System", "scannerPorts", "");
            printerPorts = ReadString(ini, "System", "printerPorts", "");
            aduinoPort = ReadString(ini, "System", "aduinoPort");
            aduinoSwVer = ReadString(ini, "System", "aduinoSwVer", "1.0");  // 기본값 1.0

            alpha = ReadDouble(ini, "Etc", "alpha");

            Volt.GraphMin = ReadInt(ini, "Volt", "graphMin");
            Volt.GraphMax = ReadInt(ini, "Volt", "graphMax");

            Amp.GraphMin = ReadInt(ini, "Amp", "graphMin");
            Amp.GraphMax = ReadInt(ini, "Amp", "graphMax");

            Flow.GraphMin = ReadInt(ini, "Flow", "graphMin");
            Flow.GraphMax = ReadInt(ini, "Flow", "graphMax");

            HoldOption = ReadString(ini, "System", "HoldOption");
            HoldSignal = ReadInt(ini, "System", "HoldSignal");

            language = ReadString(ini, "System", "Language", "한글");  // 기본값 한글
            useImageFeature = ReadString(ini, "System", "UseImageFeature", "true") == "true";

            // 용접 모드 설정
            weldMode = ReadString(ini, "Weld", "Mode", "CO2");
            spotWeldThreshold = TryGetDouble(ini, "Weld", "SpotThreshold", 2.0);
            spotUseVolt = ReadString(ini, "Weld", "SpotUseVolt", "True") == "True";
            spotUseFlow = ReadString(ini, "Weld", "SpotUseFlow", "True") == "True";

        }

        private static string ReadString(IniFile ini, string section, string key, string defaultValue = "0")
        {
            string tmp = ini.ReadValue(section, key);
            return string.IsNullOrWhiteSpace(tmp) ? defaultValue : tmp;
        }

        private static int ReadInt(IniFile ini, string section, string key, int defaultValue = 0)
        {
            string tmp = ini.ReadValue(section, key);
            return int.TryParse(tmp, out int result) ? result : defaultValue;
        }

        private static double ReadDouble(IniFile ini, string section, string key, double defaultValue = 0)
        {
            string tmp = ini.ReadValue(section, key);
            return double.TryParse(tmp, out double result) ? result : defaultValue;
        }

        public static void SaveChannelSettingsToIni()
        {
            IniFile ini = new IniFile(GetConfigPath());

            ini.WriteValue("System", "PassWord", strPassWord ?? "0");
            ini.WriteValue("System", "Title", strTitle ?? "0");
            ini.WriteValue("System", "scannerPort", scannerPort ?? "0");
            ini.WriteValue("System", "printerPort", printerPort ?? "0");
            ini.WriteValue("System", "scannerPorts", scannerPorts ?? "");
            ini.WriteValue("System", "printerPorts", printerPorts ?? "");
            ini.WriteValue("System", "aduinoPort", aduinoPort ?? "0");
            ini.WriteValue("System", "aduinoSwVer", aduinoSwVer ?? "1.0");

            ini.WriteValue("Etc", "alpha", alpha.ToString());

            ini.WriteValue("Volt", "graphMin", Volt.GraphMin.ToString());
            ini.WriteValue("Volt", "graphMax", Volt.GraphMax.ToString());
            ini.WriteValue("Amp", "graphMin", Amp.GraphMin.ToString());
            ini.WriteValue("Amp", "graphMax", Amp.GraphMax.ToString());
            ini.WriteValue("Flow", "graphMin", Flow.GraphMin.ToString());
            ini.WriteValue("Flow", "graphMax", Flow.GraphMax.ToString());

            ini.WriteValue("System", "HoldOption", HoldOption.ToString());
            ini.WriteValue("System", "HoldSignal", HoldSignal.ToString());

            ini.WriteValue("System", "Language", language ?? "한글");
            ini.WriteValue("System", "UseImageFeature", useImageFeature ? "true" : "false");

            // 용접 모드 설정
            ini.WriteValue("Weld", "Mode", weldMode ?? "CO2");
            ini.WriteValue("Weld", "SpotThreshold", spotWeldThreshold.ToString());
            ini.WriteValue("Weld", "SpotUseVolt", spotUseVolt.ToString());
            ini.WriteValue("Weld", "SpotUseFlow", spotUseFlow.ToString());

        }
    }

}

