namespace WeldMonitor3
{
    public class FilteredValue
    {
        private double filtered = 0;
        private readonly double alpha;

        public FilteredValue(double alpha)
        {
            this.alpha = alpha;
        }

        public double Update(double newValue)
        {
            filtered = alpha * newValue + (1 - alpha) * filtered;
            return filtered;
        }
    }
    public class pColor
    {
