    /// <summary>
    /// PLC word-level I/O arrays with bit access helpers.
    /// PlcIn: read from PLC (input), PlcOut: write to PLC (output).
    /// Thread-safe write via lock on _outLock.
    /// </summary>
    public static class PLC
    {
        public const int MAX_WORDS = 100;
        public static readonly int[] In = new int[MAX_WORDS];
        public static readonly int[] Out = new int[MAX_WORDS];
        private static readonly object _outLock = new object();

        public static bool GetBit(int[] arr, int wordIdx, int bitIdx)
            => (arr[wordIdx] >> bitIdx & 1) == 1;

        public static void SetBit(int wordIdx, int bitIdx, bool value)
        {
            lock (_outLock)
            {
                if (value)
                    Out[wordIdx] |= (1 << bitIdx);
                else
                    Out[wordIdx] &= ~(1 << bitIdx);
            }
        }

        public static void SetWord(int wordIdx, int value)
        {
            lock (_outLock) { Out[wordIdx] = value; }
        }

        public static int[] GetOutSnapshot()
        {
            lock (_outLock)
            {
                int[] copy = new int[MAX_WORDS];
                Array.Copy(Out, copy, MAX_WORDS);
                return copy;
            }
        }
    }
