    public class LocalizedCategoryAttribute : CategoryAttribute
    {
        private readonly string _korName;
        private readonly string _engName;
        private readonly string _korNameSpot;
        private readonly string _engNameSpot;

        public LocalizedCategoryAttribute(string korName, string engName) : base(korName)
        {
            _korName = korName;
            _engName = engName;
            _korNameSpot = korName;
            _engNameSpot = engName;
        }

        /// <summary>
        /// SPOT 모드일 때 대체 카테고리명 지정
        /// </summary>
        public LocalizedCategoryAttribute(string korName, string engName, string korNameSpot, string engNameSpot) : base(korName)
        {
            _korName = korName;
            _engName = engName;
            _korNameSpot = korNameSpot;
            _engNameSpot = engNameSpot;
        }

        protected override string GetLocalizedString(string value)
        {
            bool isSpot = GlobalValues.weldMode == "SPOT";
            if (GlobalValues.language == "English")
                return isSpot ? _engNameSpot : _engName;
            else
                return isSpot ? _korNameSpot : _korName;
        }
    }

