        public void Apply()
        {
            if (Alpha < 0.1 || Alpha > 1.0)
            {
                MessageBox.Show(Form.ActiveForm, LanguageManager.Get("msg_alpha_invalid"), LanguageManager.Get("msg_invalid_value"), MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            // 기존 언어 저장 (변경 감지용)
            string oldLanguage = GlobalValues.language;

            GlobalValues.aduinoPort = AduionoPort;
            GlobalValues.aduinoSwVer = AduinoSwVer;

            GlobalValues.strPassWord = strPassWord;

            Volt.GraphMin = VoltGraphMin;
            Volt.GraphMax = VoltGraphMax;

            Amp.GraphMin = AmpGraphMin;
            Amp.GraphMax = AmpGraphMax;

            Flow.GraphMin = FlowGraphMin;
            Flow.GraphMax = FlowGraphMax;

            GlobalValues.alpha = Alpha;
            GlobalValues.HoldOption = holdoption;
            GlobalValues.HoldSignal = holdsignal;

            GlobalValues.strTitle = strtitle;
            GlobalValues.language = language;

            // 이미지 기능 설정 변경
            bool oldUseImageFeature = GlobalValues.useImageFeature;
            GlobalValues.useImageFeature = (useImageFeature == "use");

            // 언어가 변경되었으면 모든 열려있는 폼의 언어 즉시 적용
            if (oldLanguage != language)
            {
                ApplyLanguageToAllForms();
            }

            // 이미지 기능 설정이 변경되었으면 레이아웃 적용
            if (oldUseImageFeature != GlobalValues.useImageFeature)
            {
                ApplyImageFeatureLayoutToMainForm();
            }

            // 용접 모드 설정 적용
            GlobalValues.weldMode = weldMode;
            GlobalValues.spotWeldThreshold = spotWeldThreshold;
            bool oldSpotUseVolt = GlobalValues.spotUseVolt;
            bool oldSpotUseFlow = GlobalValues.spotUseFlow;
            GlobalValues.spotUseVolt = spotUseVolt;
            GlobalValues.spotUseFlow = spotUseFlow;

            // SPOT 모드에서 Volt/Flow 사용 설정이 변경되었으면 그래프 레이아웃 적용
            if (weldMode == "SPOT" && (oldSpotUseVolt != spotUseVolt || oldSpotUseFlow != spotUseFlow))
            {
                ApplyGraphLayoutToMainForm();
            }
        }

        private void ApplyLanguageToAllForms()
        {
            // Application.OpenForms는 열려있는 모든 폼을 반환
            foreach (Form form in Application.OpenForms)
            {
                // 리플렉션으로 ApplyLanguage 메서드가 있는지 확인하고 호출
                var method = form.GetType().GetMethod("ApplyLanguage",
                    System.Reflection.BindingFlags.NonPublic |
                    System.Reflection.BindingFlags.Public |
                    System.Reflection.BindingFlags.Instance);

                if (method != null)
                {
                    method.Invoke(form, null);
                }
            }
        }

        private void ApplyImageFeatureLayoutToMainForm()
        {
            // 메인 폼 찾아서 ApplyImageFeatureLayout 호출
            foreach (Form form in Application.OpenForms)
            {
                if (form.GetType().Name == "_FrmMain")
                {
                    var method = form.GetType().GetMethod("ApplyImageFeatureLayout",
                        System.Reflection.BindingFlags.NonPublic |
                        System.Reflection.BindingFlags.Public |
                        System.Reflection.BindingFlags.Instance);

                    if (method != null)
                    {
                        method.Invoke(form, null);
                    }
                    break;
                }
            }
        }

        private void ApplyGraphLayoutToMainForm()
        {
            // 메인 폼 찾아서 ApplyGraphLayout 호출
            foreach (Form form in Application.OpenForms)
            {
                if (form.GetType().Name == "_FrmMain")
                {
                    var method = form.GetType().GetMethod("ApplyGraphLayout",
                        System.Reflection.BindingFlags.NonPublic |
                        System.Reflection.BindingFlags.Public |
                        System.Reflection.BindingFlags.Instance);

                    if (method != null)
                    {
                        method.Invoke(form, null);
                    }
                    break;
                }
            }
        }

