namespace WeldMonitor3
{
    /// <summary>
    /// 다국어 지원 Category Attribute
    /// SPOT 모드일 때 대체 이름 지원
    /// </summary>
    public class LocalizedCategoryAttribute : CategoryAttribute
    {
        private readonly string _korName;
        private readonly string _engName;
        private readonly string _korNameSpot;
        private readonly string _engNameSpot;

        public LocalizedCategoryAttribute(string korName, string engName) : base(korName)
        {
            _korName = korName;
            _engName = engName;
            _korNameSpot = korName;
            _engNameSpot = engName;
        }

        /// <summary>
        /// SPOT 모드일 때 대체 카테고리명 지정
        /// </summary>
        public LocalizedCategoryAttribute(string korName, string engName, string korNameSpot, string engNameSpot) : base(korName)
        {
            _korName = korName;
            _engName = engName;
            _korNameSpot = korNameSpot;
            _engNameSpot = engNameSpot;
        }

        protected override string GetLocalizedString(string value)
        {
            bool isSpot = GlobalValues.weldMode == "SPOT";
            if (GlobalValues.language == "English")
                return isSpot ? _engNameSpot : _engName;
            else
                return isSpot ? _korNameSpot : _korName;
        }
    }

    /// <summary>
    /// 다국어 지원 DisplayName Attribute
    /// </summary>
    public class LocalizedDisplayNameAttribute : DisplayNameAttribute
    {
        private readonly string _korName;
        private readonly string _engName;

        public LocalizedDisplayNameAttribute(string korName, string engName) : base(korName)
        {
            _korName = korName;
            _engName = engName;
        }

        public override string DisplayName
        {
            get { return GlobalValues.language == "English" ? _engName : _korName; }
        }
    }

    public class Configuration : ICustomTypeDescriptor
    {
        #region ICustomTypeDescriptor 구현 (SPOT 모드 전용 설정 필터링)

        public AttributeCollection GetAttributes() => TypeDescriptor.GetAttributes(this, true);
        public string GetClassName() => TypeDescriptor.GetClassName(this, true);
        public string GetComponentName() => TypeDescriptor.GetComponentName(this, true);
        public TypeConverter GetConverter() => TypeDescriptor.GetConverter(this, true);
        public EventDescriptor GetDefaultEvent() => TypeDescriptor.GetDefaultEvent(this, true);
        public PropertyDescriptor GetDefaultProperty() => TypeDescriptor.GetDefaultProperty(this, true);
        public object GetEditor(Type editorBaseType) => TypeDescriptor.GetEditor(this, editorBaseType, true);
        public EventDescriptorCollection GetEvents() => TypeDescriptor.GetEvents(this, true);
        public EventDescriptorCollection GetEvents(Attribute[] attributes) => TypeDescriptor.GetEvents(this, attributes, true);
        public object GetPropertyOwner(PropertyDescriptor pd) => this;

        public PropertyDescriptorCollection GetProperties() => GetProperties(null);

        public PropertyDescriptorCollection GetProperties(Attribute[] attributes)
        {
            var props = TypeDescriptor.GetProperties(this, attributes, true);
            var filtered = new List<PropertyDescriptor>();

            foreach (PropertyDescriptor prop in props)
            {
                // SPOT 모드가 아니면 SPOT 전용 설정 숨김
                if (weldMode != "SPOT" &&
                    (prop.Name == "spotWeldThreshold" || prop.Name == "spotUseVolt" || prop.Name == "spotUseFlow"))
                {
                    continue;
                }

                filtered.Add(prop);
            }

            return new PropertyDescriptorCollection(filtered.ToArray());
        }

        #endregion

