using System.Collections.ObjectModel;
using System.Windows;
using System.Windows.Media;
using LiveChartsCore;
using LiveChartsCore.SkiaSharpView;
using LiveChartsCore.SkiaSharpView.Painting;
using SkiaSharp;
using MaterialDesignThemes.Wpf;

namespace WeldMonitorV2;

public partial class MainWindow : DialogHost
{
    // Chart data
    private readonly ObservableCollection<double> _ampValues = new();
    private readonly ObservableCollection<double> _voltValues = new();
    private readonly ObservableCollection<double> _flowValues = new();

    public MainWindow()
    {
        InitializeComponent();
        InitCharts();
        LoadDemoData();
    }

    private void InitCharts()
    {
        chartAmp.Series = CreateSeries(_ampValues, new SKColor(79, 195, 247));   // light blue
        chartVolt.Series = CreateSeries(_voltValues, new SKColor(129, 199, 132)); // light green
        chartFlow.Series = CreateSeries(_flowValues, new SKColor(255, 183, 77));  // orange

        var xAxis = new Axis { IsVisible = false };
        var yAxisStyle = new Axis
        {
            LabelsPaint = new SolidColorPaint(new SKColor(150, 150, 150)),
            SeparatorsPaint = new SolidColorPaint(new SKColor(50, 50, 50)),
        };

        chartAmp.XAxes = new[] { xAxis };
        chartAmp.YAxes = new[] { CloneYAxis(yAxisStyle) };
        chartVolt.XAxes = new[] { new Axis { IsVisible = false } };
        chartVolt.YAxes = new[] { CloneYAxis(yAxisStyle) };
        chartFlow.XAxes = new[] { new Axis { IsVisible = false } };
        chartFlow.YAxes = new[] { CloneYAxis(yAxisStyle) };
    }

    private static ISeries[] CreateSeries(ObservableCollection<double> values, SKColor color)
    {
        return new ISeries[]
        {
            new LineSeries<double>
            {
                Values = values,
                Stroke = new SolidColorPaint(color, 2),
                Fill = new SolidColorPaint(color.WithAlpha(30)),
                GeometrySize = 0,
                LineSmoothness = 0.3,
            }
        };
    }

    private static Axis CloneYAxis(Axis template)
    {
        return new Axis
        {
            LabelsPaint = template.LabelsPaint,
            SeparatorsPaint = template.SeparatorsPaint,
        };
    }

    private void LoadDemoData()
    {
        // Demo waveform data
        var rng = new Random(42);
        for (int i = 0; i < 100; i++)
        {
            double t = i / 100.0;
            bool welding = t > 0.2 && t < 0.8;
            _ampValues.Add(welding ? 240 + rng.NextDouble() * 20 - 10 : rng.NextDouble() * 2);
            _voltValues.Add(welding ? 23 + rng.NextDouble() * 3 - 1.5 : rng.NextDouble() * 0.5);
            _flowValues.Add(welding ? 18 + rng.NextDouble() * 2 - 1 : rng.NextDouble() * 0.3);
        }

        // Demo KPI
        txtAmp.Text = "245.30";
        txtVolt.Text = "23.10";
        txtFlow.Text = "18.20";
        txtJig.Text = "#23 LH";
        txtStep.Text = "3 / 7";
        txtResult.Text = "5 OK  0 NG";
        txtResult.Foreground = new SolidColorBrush(Color.FromRgb(129, 199, 132));

        // Status LEDs
        ledPLC.Fill = new SolidColorBrush(Color.FromRgb(129, 199, 132));
        ledArduino.Fill = new SolidColorBrush(Color.FromRgb(129, 199, 132));

        // Demo grid data
        dgResult.ItemsSource = new[]
        {
            new { Point = 1, Result = "OK", AmpAvg = 245.3, AmpMax = 252.1, AmpMin = 238.7, VoltAvg = 23.1, VoltMax = 24.2, FlowAvg = 18.2, TimeElapsed = 1.2 },
            new { Point = 2, Result = "OK", AmpAvg = 243.8, AmpMax = 250.5, AmpMin = 237.2, VoltAvg = 22.9, VoltMax = 23.8, FlowAvg = 18.0, TimeElapsed = 1.1 },
            new { Point = 3, Result = "OK", AmpAvg = 246.1, AmpMax = 253.0, AmpMin = 239.5, VoltAvg = 23.3, VoltMax = 24.5, FlowAvg = 18.4, TimeElapsed = 1.3 },
            new { Point = 4, Result = "NG", AmpAvg = 198.7, AmpMax = 210.2, AmpMin = 187.3, VoltAvg = 22.8, VoltMax = 23.5, FlowAvg = 17.5, TimeElapsed = 0.8 },
            new { Point = 5, Result = "OK", AmpAvg = 244.5, AmpMax = 251.8, AmpMin = 237.9, VoltAvg = 23.0, VoltMax = 24.0, FlowAvg = 18.1, TimeElapsed = 1.2 },
        };
    }
}

